During kind of "lock-down" weekend, I come up with some other idea which is essentially subclassing the property class.
I would like to submit to evaluation and possibly add a new PR.
In order to explain it, I would prefer to add a code snippet.
```
class DynamicProperty(property):
    """ This property redefines get and set in a "dynamic" fashion """
    def __init__(self, dynlist, fget=None, fset=None, fdel=None, doc=None):
        super().__init__(fget, fset, fdel, doc)
        self.dynlist = dynlist
        self.name = ""

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        if self.fget is None:
            raise AttributeError("unreadable attribute")

        for attr in self.dynlist:
            attr1 = "_".join([self.name,attr])
            kwargs = {}
            if hasattr(obj, attr1):
                kwargs[attr]=getattr(obj, attr1)
        return self.fget(obj, **kwargs)

    def __set__(self, obj, value):
        if self.fset is None:
            raise AttributeError("can't set attribute")
        for attr in self.dynlist:
            attr1 = "_".join([self.name,attr])
            kwargs = {}
            if hasattr(obj, attr1):
                kwargs[attr]=getattr(obj, attr1)
        self.fset(obj, value, **kwargs)

    def set_name(self, name):
        print ("Setting name: %s (old name:%s)"%(name, self.name), self)
        self.name = name

class Instrument(object):
    @staticmethod
    def property_test(values, dynamic=False, name = ""):
        param_list = ["values"] # vars().keys()
        """ Test property """
        print ("Defining property with", values)

        def fget_with_params(self, values=values):
            print ("fget: Params range is", values, self)
            return 0

        def fget(self):
            return fget_with_param(self, values)

        def fset_with_params(self, value, values=values):
            print ("fset: Params range is", values, self)

        def fset(self, value):
            return fset_with_param(self, value, values)

        if dynamic:
            return DynamicProperty(param_list, fget_with_params, fset_with_params)
        else:
            return property(fget, fset)

    def __init__(self):
        for obj in [self] + self.__class__.mro():
            for attr in obj.__dict__:
                if isinstance(obj.__dict__[attr], DynamicProperty):
                    obj.__dict__[attr].set_name(attr)

class B(Instrument):
    # Class attribute
    my_property = Instrument.property_test(values=(1,2), dynamic=True)

class C(B):
    # No inheritance, just dedicated system to set property params (<name>_<param>)
    my_property_values = (3,4)

class D(B):
    # No inheritance, just dedicated system to set property params (<name>_<param>)
    my_property_values = (5,6)

c=C()
c.my_property
d=D()
d.my_property
c.my_property
```
